  3814→        eq(costBaselines.fiscalYear, fiscalYear),
  3815→        depotId ? eq(costBaselines.depotId, depotId) : isNull(costBaselines.depotId)
  3816→      )
  3817→    });
  3818→    
  3819→    if (!baseline) {
  3820→      throw new NotFoundError('Cost baseline not found');
  3821→    }
  3822→    
  3823→    // Get actual costs from completed PMs
  3824→    const yearStart = new Date(fiscalYear, 0, 1);
  3825→    const yearEnd = new Date(fiscalYear, 11, 31);
  3826→    
  3827→    const completedPMs = await this.db.query.pmSchedule.findMany({
  3828→      where: and(
  3829→        eq(pmSchedule.status, 'COMPLETED'),
