## 4.2.7 Route Utilization Service (NEW v2.1)

### 4.2.7.1 Purpose

Provide route-specific daily mileage rates for accurate long-term projections. Using fleet-wide averages can result in 60,000+ km projection error over 12 years.

### 4.2.7.2 Implementation

```typescript
interface RouteUtilizationProfile {
  id: string;
  routeId: string;
  effectiveDate: Date;

  weekdayKm: number;
  saturdayKm?: number;
  sundayKm?: number;
  holidayKm?: number;

  peakSeasonMultiplier: number;
  offPeakMultiplier: number;

  confidence: 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
}

class RouteUtilizationService {
  constructor(private db: Database) {}

  /**
   * Get utilization profile for a route
   */
  async getProfile(routeId: string, asOfDate?: Date): Promise<RouteUtilizationProfile | null> {
    const date = asOfDate || new Date();

    const profile = await this.db
      .select()
      .from(routeUtilizationProfiles)
      .where(and(
        eq(routeUtilizationProfiles.routeId, routeId),
        lte(routeUtilizationProfiles.effectiveDate, date)
      ))
      .orderBy(desc(routeUtilizationProfiles.effectiveDate))
      .limit(1);

    return profile[0] || null;
  }

  /**
   * Calculate expected daily km for a train based on typical route assignment
   */
  async calculateDailyRate(
    trainId: string, 
    targetDate: Date
  ): Promise<{ dailyKm: number; source: string; confidence: string }> {
    // 1. Check for explicit route assignment
    const assignment = await this.getTypicalRouteAssignment(trainId);

    if (assignment) {
      const profile = await this.getProfile(assignment.routeId, targetDate);
      if (profile) {
        const dayType = this.getDayType(targetDate);
        const baseKm = this.getKmForDayType(profile, dayType);
        const seasonalMultiplier = this.getSeasonalMultiplier(profile, targetDate);

        return {
          dailyKm: Math.round(baseKm * seasonalMultiplier),
          source: `route:${assignment.routeId}`,
          confidence: profile.confidence
        };
      }
    }

    // 2. Fall back to fleet average
    const train = await this.db
      .select({ fleetId: trains.fleetId })
      .from(trains)
      .where(eq(trains.id, trainId))
      .limit(1);

    if (train[0]) {
      const fleetAverage = await this.getFleetAverage(train[0].fleetId);
      return {
        dailyKm: fleetAverage,
        source: 'fleet_average',
        confidence: 'LOW'
      };
    }

    // 3. System default
    return {
      dailyKm: 250,  // Conservative default
      source: 'system_default',
      confidence: 'ESTIMATED'
    };
  }

  /**
   * Project mileage for a train over a time horizon
   */
  async projectMileage(
    trainId: string,
    startDate: Date,
    horizonDays: number
  ): Promise<{ date: Date; projectedKm: number; cumulativeKm: number }[]> {
    const train = await this.db
      .select()
      .from(trains)
      .where(eq(trains.id, trainId))
      .limit(1);

    if (!train[0]) {
      throw new NotFoundError(`Train ${trainId} not found`);
    }

    let cumulativeKm = train[0].currentMileageKm;
    const projections: { date: Date; projectedKm: number; cumulativeKm: number }[] = [];

    for (let day = 0; day < horizonDays; day++) {
      const targetDate = addDays(startDate, day);
      const { dailyKm } = await this.calculateDailyRate(trainId, targetDate);

      cumulativeKm += dailyKm;
      projections.push({
        date: targetDate,
        projectedKm: dailyKm,
        cumulativeKm
      });
    }

    return projections;
  }

  private async getTypicalRouteAssignment(trainId: string): Promise<{ routeId: string } | null> {
    // Look at recent run assignments to determine typical route
    const recentAssignments = await this.db
      .select({ routeId: runAssignments.routeId, count: count() })
      .from(runAssignments)
      .where(and(
        eq(runAssignments.trainId, trainId),
        gte(runAssignments.assignmentDate, addDays(new Date(), -30))
      ))
      .groupBy(runAssignments.routeId)
      .orderBy(desc(count()))
      .limit(1);

    return recentAssignments[0] || null;
  }

  private async getFleetAverage(fleetId: string): Promise<number> {
    // Calculate from recent mileage readings
    const result = await this.db
      .select({ avgDaily: avg(mileageReadings.dailyKm) })
      .from(mileageReadings)
      .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
      .where(and(
        eq(trains.fleetId, fleetId),
        gte(mileageReadings.readingDate, addDays(new Date(), -30)),
        eq(mileageReadings.validationStatus, 'VALID')
      ));

    return Math.round(result[0]?.avgDaily || 250);
  }

  private getKmForDayType(profile: RouteUtilizationProfile, dayType: string): number {
    switch (dayType) {
      case 'SATURDAY': return profile.saturdayKm || profile.weekdayKm * 0.8;
      case 'SUNDAY': return profile.sundayKm || profile.weekdayKm * 0.7;
      case 'HOLIDAY': return profile.holidayKm || profile.weekdayKm * 0.6;
      default: return profile.weekdayKm;
    }
  }

  private getSeasonalMultiplier(profile: RouteUtilizationProfile, date: Date): number {
    // TODO: Integrate with season calendar
    const month = date.getMonth();
    // Peak season: CNY (Jan-Feb), School holidays (Jun, Nov-Dec)
    const peakMonths = [0, 1, 5, 10, 11];
    return peakMonths.includes(month) ? profile.peakSeasonMultiplier : profile.offPeakMultiplier;
  }

  private getDayType(date: Date): string {
    const dayOfWeek = date.getDay();
    if (dayOfWeek === 0) return 'SUNDAY';
    if (dayOfWeek === 6) return 'SATURDAY';
    return 'WEEKDAY';
  }
}
```

